using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient injected via DI.
/// Constructor injection is used because tools share the HttpClient and logger.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the API. Returns JSON array of user objects.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (1-100)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing users with limit {Limit}", limit);
        var response = await httpClient.GetStringAsync($"/users?_limit={limit}", cancellationToken);
        return FormatJson(response);
    }

    [McpServerTool, Description("Get a single user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The numeric ID of the user to retrieve")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: user {userId} not found (HTTP {(int)response.StatusCode})";

        var body = await response.Content.ReadAsStringAsync(cancellationToken);
        return FormatJson(body);
    }

    [McpServerTool, Description("Get all posts written by a specific user.")]
    public async Task<string> GetUserPosts(
        [Description("The numeric user ID whose posts to retrieve")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var response = await httpClient.GetStringAsync($"/users/{userId}/posts", cancellationToken);
        return FormatJson(response);
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Search posts by title keyword. Returns matching posts as JSON.")]
    public async Task<string> SearchPosts(
        [Description("Keyword to search for in post titles")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching posts for '{Query}'", query);
        var encoded = Uri.EscapeDataString(query);
        var response = await httpClient.GetStringAsync($"/posts?title_like={encoded}", cancellationToken);
        return FormatJson(response);
    }

    private static string FormatJson(string json)
    {
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, JsonOptions);
    }
}

