     public async Task<string> SearchPosts(
         [Description("Keyword to search for in post titles")] string query,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Searching posts for '{Query}'", query);
         var encoded = Uri.EscapeDataString(query);
         var response = await httpClient.GetStringAsync($"/posts?title_like={encoded}", cancellationToken);
         return FormatJson(response);
     }

     private static string FormatJson(string json)
     {
         using var doc = JsonDocument.Parse(json);
         return JsonSerializer.Serialize(doc, JsonOptions);
     }
 }

